-- Level 1 Quiz: Foundation QS Quiz
UPDATE academy_modules SET questions = '[
  {"question":"What does QS stand for in construction?","options":["Quality Specialist","Quantity Surveyor","Quick Supplier","Quantum Specialist"],"correct":1,"explanation":"QS stands for Quantity Surveyor — the financial manager of construction projects."},
  {"question":"Which professional body regulates QS practice in Nigeria?","options":["RICS","NIQS","QSRBN","COREN"],"correct":2,"explanation":"QSRBN (Quantity Surveyors Registration Board of Nigeria) is the statutory regulator."},
  {"question":"What is the primary output of a quantity surveyor?","options":["Architectural drawings","Cost plans and bills of quantities","Structural calculations","Site instructions"],"correct":1,"explanation":"QS professionals produce cost plans, bills of quantities, and financial reports."},
  {"question":"Which drawing type shows load-bearing elements?","options":["Architectural","Structural","M&E","Civil"],"correct":1,"explanation":"Structural drawings show foundations, beams, columns, and slabs."},
  {"question":"At what scale are floor plans typically drawn?","options":["1:5","1:20","1:50","1:100"],"correct":2,"explanation":"Floor plans are typically drawn at 1:50 scale."},
  {"question":"What does FFL stand for on a drawing?","options":["Final Floor Level","Finished Floor Level","First Floor Level","Full Floor Load"],"correct":1,"explanation":"FFL stands for Finished Floor Level — the top surface of the floor."},
  {"question":"How many membership grades does NIQS have?","options":["3","4","5","6"],"correct":3,"explanation":"NIQS has 6 grades: Student, Technician, Graduate, Associate, Member, and Fellow."}
]' WHERE pathway_slug = 'technical-qs-practice' AND level = 1 AND module_type = 'quiz';

-- Level 2 Quiz: Measurement & Quantification Quiz
UPDATE academy_modules SET questions = '[
  {"question":"Under SMM7, what unit is excavation measured in?","options":["m²","m³","nr","kg"],"correct":1,"explanation":"Excavation is measured in cubic metres (m³)."},
  {"question":"How many 9-inch blocks are needed per m² of wall?","options":["8","10","12","14"],"correct":1,"explanation":"Standard measurement: 10 blocks per m² for 9-inch (225mm) blockwork."},
  {"question":"What is the dry-to-wet volume conversion factor for concrete?","options":["1.35","1.50","1.54","1.60"],"correct":2,"explanation":"The factor is 1.54 to account for shrinkage and voids in dry materials."},
  {"question":"What thickness is standard internal plastering?","options":["10mm","12mm","15mm","20mm"],"correct":2,"explanation":"Standard internal plastering is 15mm thick in cement mortar 1:4."},
  {"question":"What is the minimum opening size for deduction in blockwork?","options":["0.1 m²","0.2 m²","0.3 m²","0.5 m²"],"correct":2,"explanation":"Openings over 0.3 m² are deducted from blockwork measurement."},
  {"question":"Which SMM7 rule governs concrete measurement?","options":["Rule 1","Rule 2","Rule 3","Rule 4"],"correct":2,"explanation":"Rule 3 covers the measurement of concrete works under SMM7."},
  {"question":"What unit are doors measured in under SMM7?","options":["m²","m³","nr","kg"],"correct":2,"explanation":"Doors are measured in numbers (nr) under SMM7."}
]' WHERE pathway_slug = 'technical-qs-practice' AND level = 2 AND module_type = 'quiz';

-- Level 3 Quiz: Advanced Measurement Assessment
UPDATE academy_modules SET questions = '[
  {"question":"What is the first section of a standard BOQ?","options":["Measured works","Preliminaries","Provisional sums","Prime cost sums"],"correct":1,"explanation":"Section A contains preliminaries — site establishment, temporary works, etc."},
  {"question":"What percentage is typically held as retention?","options":["2.5%","5%","7.5%","10%"],"correct":1,"explanation":"5% retention is standard, held until practical completion (half) and defects liability (balance)."},
  {"question":"Which rate build-up component typically has the highest percentage?","options":["Materials","Labour","Overheads","Profit"],"correct":0,"explanation":"Materials typically represent 40-60% of the total rate."},
