-- Level 2 Quiz: Claims Workshop Assessment
UPDATE academy_modules SET questions = '[
  {"question":"What is the primary purpose of a claims notice?","options":["To threaten the other party","To preserve contractual rights","To end the contract","To request payment"],"correct":1,"explanation":"A claims notice preserves contractual rights and prevents time bar defences."},
  {"question":"What is causation in claims?","options":["The cost of the claim","The link between the event and the loss","The contract terms","The dispute resolution method"],"correct":1,"explanation":"Causation is the link between the qualifying event and the resulting loss or delay."},
  {"question":"What is the most important evidence in claims?","options":["Expert opinion","Contemporaneous records","Legal arguments","Public opinion"],"correct":1,"explanation":"Contemporaneous records (made at the time) are the most credible evidence."},
  {"question":"What is a without-prejudice meeting?","options":["A court hearing","A settlement discussion that cannot be used as evidence","A public meeting","A contract negotiation"],"correct":1,"explanation":"Without-prejudice discussions are confidential and cannot be referred to in later proceedings."},
  {"question":"What is the standard of proof in construction disputes?","options":["Beyond reasonable doubt","On the balance of probabilities","Beyond any doubt","With certainty"],"correct":1,"explanation":"Civil construction disputes use the balance of probabilities standard."},
  {"question":"What is quantum in claims?","options":["The number of claims","The amount of damages claimed","The speed of resolution","The quality of evidence"],"correct":1,"explanation":"Quantum refers to the amount of damages or additional cost being claimed."},
  {"question":"What is a liquidated damages clause?","options":["A penalty for poor quality","Pre-agreed compensation for delay","A bonus for early completion","A cost escalation clause"],"correct":1,"explanation":"Liquidated damages are pre-agreed daily amounts payable for each day of delay."}
]' WHERE pathway_slug = 'dispute-resolution' AND level = 2 AND module_type = 'quiz';

