  {"question":"What referencing style is most common in construction research?","options":["Chicago","Harvard/APA","MLA","Vancouver"],"correct":1,"explanation":"Harvard or APA referencing style is most commonly used in construction and engineering research."},
  {"question":"What is a research question?","options":["A question asked in an interview","A specific question the research aims to answer","A question from the supervisor","A survey question"],"correct":1,"explanation":"A research question is the central question that the entire research study aims to answer."},
  {"question":"What is a hypothesis?","options":["A confirmed fact","A testable prediction about the relationship between variables","A research conclusion","A data collection method"],"correct":1,"explanation":"A hypothesis is a testable prediction about the expected relationship between variables."},
  {"question":"What is the purpose of an abstract?","options":["To introduce the author","To summarise the entire paper in 250 words","To list references","To acknowledge funding"],"correct":1,"explanation":"An abstract provides a concise summary of the research, including objectives, methods, and findings."},
  {"question":"What is academic integrity?","options":["Writing quickly","Honest and ethical conduct in research and writing","Using complex vocabulary","Citing many sources"],"correct":1,"explanation":"Academic integrity means honest and ethical conduct, including proper citation and no plagiarism."}
