UPDATE academy_modules SET questions = '[
  {"question":"What is a literature review?","options":["Reading one book","Critically evaluating and synthesising existing research","Writing a novel","Creating a bibliography"],"correct":1,"explanation":"A literature review critically evaluates and synthesises existing research on a topic."},
  {"question":"What is a survey?","options":["A site inspection","A structured data collection method using questions","A financial audit","A contract review"],"correct":1,"explanation":"A survey is a structured data collection method using standardised questions administered to a sample."},
  {"question":"What is triangulation in research?","options":["Using a compass","Using multiple data sources to validate findings","Three researchers working together","A type of sampling"],"correct":1,"explanation":"Triangulation uses multiple data sources or methods to cross-validate research findings."},
